// Simple Result type (tự implement)
public readonly struct Result<T>
{
    public T? Value { get; }
    public string? Error { get; }
    public bool IsSuccess => Error is null;

    private Result(T value) { Value = value; Error = null; }
    private Result(string error) { Value = default; Error = error; }

    public static Result<T> Ok(T value) => new(value);
    public static Result<T> Fail(string error) => new(error);

    public Result<TOut> Map<TOut>(Func<T, TOut> mapper) =>
        IsSuccess ? Result<TOut>.Ok(mapper(Value!)) : Result<TOut>.Fail(Error!);
}

// Domain service
public async Task<Result<Order>> CreateOrderAsync(CreateOrderDto dto, CancellationToken ct)
{
    var customer = await _repo.GetCustomerAsync(dto.CustomerId, ct);
    if (customer is null)
        return Result<Order>.Fail($"Customer {dto.CustomerId} not found");

    if (!customer.HasSufficientBalance(dto.Total))
        return Result<Order>.Fail("Insufficient balance");

    var order = await _repo.CreateAsync(dto, ct);
    return Result<Order>.Ok(order);
}

// Controller/Endpoint map result → HTTP
app.MapPost("/api/orders", async (CreateOrderDto dto, OrderService svc, CancellationToken ct) =>
{
    var result = await svc.CreateOrderAsync(dto, ct);
    return result.IsSuccess
        ? Results.Created($"/api/orders/{result.Value!.Id}", result.Value)
        : Results.BadRequest(new { error = result.Error });
});
